queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?rolename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:RoleID ?cg . ?child a :Financial_Roles ; p:RoleID ?cg . ?l p:BankID ?pg . ?parent a :Banks ; p:BankID ?pg . } GROUP BY ?child }
  ?child p:RoleName ?rolename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Banks } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?rolename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:RoleID ?cg . ?child a :Financial_Roles ; p:RoleID ?cg . ?l p:BankID ?pg . ?parent a :Banks ; p:BankID ?pg . } GROUP BY ?child }
  ?child p:RoleName ?rolename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Banks } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?rolename WHERE {
  ?banks_financial_roles a :Banks_Financial_Roles .
  ?financial_roles a :Financial_Roles .
  ?banks_financial_roles p:hasFinancial_Roles ?financial_roles .
  ?banks a :Banks .
  ?banks_financial_roles p:hasBanks ?banks .
  ?banks p:name ?name .
  ?financial_roles p:RoleName ?rolename .
} }
}
